INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00077', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警方正在偵辦一起詐欺案件，據線報指出甲涉嫌重大，於是警員P製作一張「通知單」通知 甲至警局接受詢問，未蓋分局長章，直接拿到甲之住處，因甲不在，而由鄰居代收。甲依通 知到警局，等候3個小時卻仍未開始詢問，警方解釋現在太忙，請其稍待片刻；片刻後，由 警員P對甲進行詢問，P於詢問前先核對了甲之身分，並進行告知義務，甲表示了解、並無 請律師的需求。隨後，P詢問甲對於詐欺案件的看法，甲一概否認；由於中途P發現忘記攜 帶錄音設備，於是決定先問完後，請甲照著筆錄念一遍，進行補錄音。甲在重述的過程中， 意識到自己講了不該講的話，涉嫌重大，遂情緒失控，準備突圍逃跑；P發現甲之異狀，遂 逕行拘提甲，並於事後報請檢察官核發拘票。請根據上述事實判斷，下列敘述何者正確？', '["通知書必須按照法定格式製作，除須記載犯罪嫌疑人之姓名及可辨識身分資料、涉嫌之罪 名、應到之日時及處所、特別事項外，尚要載明無正當理由不到場者，得命拘提，並經地 區警察分局長或相當職務之長官簽章。故本件P製作之通知書不合法", "犯罪嫌疑人到場後，原則上應依原定時間及處所即時詢問，不得無故拖延；但如有重要案 件須處理或經犯罪嫌疑人同意時，得依實際情形，調整詢問時間或使其在現場等候。故本 件P請甲等候詢問之行為合法", "詢問犯罪嫌疑人時應全程連續錄音；必要時，應全程連續錄影。不得於筆錄製作完成後， 始重新詢問並要求受詢問人照筆錄朗讀再予錄音；就算徵得被詢問人之同意，亦違反相關 法律之規定而不合法。故本件P要求甲重錄之行為不合法", "有刑事訴訟法第88條之1第1項各款情形之一，且情況急迫不及報告檢察官者，得逕行 拘提之。惟於執行後，應即報請檢察官簽發拘票，如檢察官不簽發拘票時，應即將被拘提 人釋放。故本件P逕行拘提甲之行為合法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00078', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於告訴，根據我國刑事訴訟法及相關規定，下列敘述何者正確？', '["滿18歲之甲遭人毆傷，其父A於事發後3個月至警察局代甲提出刑事告訴，並表示甲因 為害怕報復而不敢親自前來提告", "乙目睹扒手行竊，便到最近的派出所舉報，描述了整個犯罪經過，卻因為無法提供扒手的 真實姓名而無法完成告訴", "丙在1月1日發現自己的手機被同學B偷走，但拖到7月15日才到警局對B提出告訴； 該告訴因已逾告訴期間而不合法，檢察官僅能以不起訴終結程序", "丁因遭C誹謗後不久意外死亡，其兄至警察局代為對C提起告訴，該告訴應屬合法有效， 警方應予受理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00079', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官帶同被告前往轄區外追查贓證共犯，預計不能於當日返回者，應事先請准該管檢 察官檢附原押票影本行文當地看守所，將被告暫寄押於該看守所，其寄押期間為何？', '["不得逾24小時", "不得逾3日", "不得逾5日", "不得逾7日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00080', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於無令狀搜索之規定，下列敘述何者正確？', '["司法警察官因追躡現行犯，得逕行搜索其所使用之交通工具", "緊急搜索是屬於對人的搜索，目的在於逮捕被告、犯罪嫌疑人或執行拘提、羈押", "司法警察官經房東之自願性同意，得搜索承租房客個人居住之房間", "司法警察官依刑事訴訟法第130條規定實施附帶搜索後，並無3日內報告檢察官及法院之 規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00081', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於刑事訴訟法鑑定之規定，下列敘述何者正確？', '["鑑定人應於鑑定前具結，其結文內應記載當據實陳述，決無匿、飾、增、減等語", "鑑定人在檢察官訊問時並未具結，但作成了與事實相符的陳述，鑑定人的陳述有證據能力", "因鑑定被告心神或身體之必要而進行鑑定留置，每次2個月，必要時得延長1次", "鑑定證人本質上是證人，具有不可代替性，適用關於人證之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00082', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於證據有湮滅、偽造、變造、隱匿或礙難使用之虞時之證據保全規定，下列何者正確？', '["檢察官於偵查中應向該管法院聲請之", "告訴人、被告或辯護人於法院審判中，應向該管法院聲請之", "案件尚未移送檢察官者，應向調查之司法警察機關聲請之", "聲請人依法向法院聲請保全證據，經法院為准許之裁定者，檢察官不得抗告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00083', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察於命案發生後在現場進行勘察屍體時，若於屍體上發現下列何種外部徵狀者，得供 為辨明死者可能係自殺之初步參據？', '["上吊屍體之頸後部沒有繩索溝痕者", "槍傷屍體之射擊距離在20公分以上者", "屍體已掩埋且現場跡證被湮滅者", "屍體上有2種以上之兇器創傷者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00084', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依家庭暴力防治法規定，下列何者為警政主管機關之權責事項？', '["家庭暴力犯罪之刑事案件資料統計", "家庭暴力被害人之驗傷、採證", "家庭暴力犯罪之再犯預防", "定期公布家庭暴力之相關統計"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00085', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依少年事件處理法規定，司法警察官逮捕少年時，其所觸犯之刑罰法律顯係最重本刑為幾年 以下有期徒刑時，得填載不護送報告書，以傳真或其他適當方式，報請該管少年法院法官許 可後，不予護送，逕行釋放？', '["1年", "2年", "3年", "5年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00086', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '依托咪酯（Etomidate，又稱為喪屍菸彈）屬於中樞神經鎮定劑的麻醉藥物；吩坦尼（Fentanyl， 又稱為芬太尼），是強效合成的鴉片類止痛藥物。請問：這2類藥物在臺灣目前被核定為那 一級的毒品？', '["前者為第二級毒品，後者為第二級毒品", "前者為第二級毒品，後者為第三級毒品", "前者為第三級毒品，後者為第二級毒品", "前者為第三級毒品，後者為第三級毒品"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
